// frontend/src/DashboardAluno.js
import React, { useEffect, useState } from "react";
import { useAuth } from "./context/AuthContext";
import axios from "axios";

export default function DashboardAluno() {
  const { user } = useAuth();
  const [meusAgendamentos, setMeusAgendamentos] = useState([]);
  const [carregando, setCarregando] = useState(true);

  useEffect(() => {
    setCarregando(true);
    axios
      .get("/api/agendamentos") // nosso backend devolve só do aluno logado
      .then((res) => {
        setMeusAgendamentos(res.data);
        setCarregando(false);
      })
      .catch((err) => {
        console.error(err);
        setCarregando(false);
      });
  }, []);

  if (carregando) {
    return <p>Carregando seu resumo...</p>;
  }

  const pendentes = meusAgendamentos.filter((a) => a.status === "Pendente");
  const aprovados = meusAgendamentos.filter((a) => a.status === "Aprovada");
  // etc.

  return (
    <div className="max-w-3xl mx-auto py-10 px-4">
      <h1 className="text-3xl font-bold mb-8">Olá, {user.nome}!</h1>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
        <div className="bg-blue-100 rounded-2xl shadow p-6">
          <div className="text-lg font-semibold mb-2">Total de Agendamentos</div>
          <div className="font-bold text-2xl text-[#3172C0]">
            {meusAgendamentos.length}
          </div>
        </div>
        <div className="bg-yellow-100 rounded-2xl shadow p-6">
          <div className="text-lg font-semibold mb-2">Pendentes</div>
          <div className="font-bold text-2xl text-[#C97F00]">
            {pendentes.length}
          </div>
        </div>
        {/* outros widgets, ex.: Aprovados, Cancelados, etc. */}
      </div>
      <div className="bg-white rounded-2xl shadow p-6">
        <div className="text-lg font-semibold mb-4">Meus Próximos Agendamentos</div>
        {meusAgendamentos.length === 0 && <p>Não há agendamentos futuros.</p>}
        {meusAgendamentos.map((a) => (
          <div
            key={a.id}
            className="flex justify-between items-center border-b py-2"
          >
            <div>
              <p className="font-medium">
                {new Date(a.data_hora).toLocaleString("pt-BR", {
                  dateStyle: "short",
                  timeStyle: "short",
                })}
              </p>
              <p className="text-gray-600">{a.paciente_nome}</p>
            </div>
            <span className="px-3 py-1 rounded-full bg-green-100 text-green-800 text-sm">
              {a.status}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}
